// // This module de-interleaves the bits of two 2-bit inputs e[1:0] and f[1:0], producing a 4-bit output d[3:0] where d[3] is e[0], d[2] is f[0], d[1] is e[1], and d[0] is f[1].
module interleave (
	input [1:0] e,
	input [1:0] f,
	output [3:0] d);assign d = {e[1], f[1], e[0], f[0]};

endmodule
